import type { NavFloorGpsBounds } from '@shared/types'

export interface FloorGpsBoundsColumns {
  gpsMinLat: number | null
  gpsMaxLat: number | null
  gpsMinLng: number | null
  gpsMaxLng: number | null
}

function isFiniteNumber(value: number | null): value is number {
  return value !== null && Number.isFinite(value)
}

/**
 * Converts nullable DB floor GPS columns into a complete GPS bounds object.
 * Returns null when any value is missing (or non-finite), ensuring callers never
 * serialize partial coordinate tuples.
 */
export function toNavFloorGpsBounds(row: FloorGpsBoundsColumns): NavFloorGpsBounds | null {
  if (
    !isFiniteNumber(row.gpsMinLat)
    || !isFiniteNumber(row.gpsMaxLat)
    || !isFiniteNumber(row.gpsMinLng)
    || !isFiniteNumber(row.gpsMaxLng)
  ) {
    return null
  }

  return {
    minLat: row.gpsMinLat,
    maxLat: row.gpsMaxLat,
    minLng: row.gpsMinLng,
    maxLng: row.gpsMaxLng,
  }
}

export function serializeFloorGpsBounds(row: FloorGpsBoundsColumns): { gpsBounds?: NavFloorGpsBounds } {
  const gpsBounds = toNavFloorGpsBounds(row)
  return gpsBounds ? { gpsBounds } : {}
}

import { readFile } from 'node:fs/promises'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'
import { r2GetBuffer, r2PutBuffer } from './r2'
import { serve } from '@hono/node-server'
import { serveStatic } from '@hono/node-server/serve-static'
import type { NavGraph, NavNode } from '@shared/types'
import { drizzle as drizzlePg } from 'drizzle-orm/postgres-js'
import { migrate } from 'drizzle-orm/postgres-js/migrator'
import { and, eq, inArray } from 'drizzle-orm'
import postgres from 'postgres'
import { Hono } from 'hono'
import { csrf } from 'hono/csrf'
import { jwt } from 'hono/jwt'
import { JWT_SECRET } from './auth/credentials'
import { authRoutes } from './auth/routes'
import { ConnectorLinkingError, linkConnectorNodesFromPayload } from './connectorLinking'
import { db } from './db/client'
import { buildings, edges, floors, nodes } from './db/schema'
import { serializeFloorGpsBounds } from './floorGpsBounds'
import { seedIfEmpty } from './db/seed'

const __dirname = dirname(fileURLToPath(import.meta.url))

// ── Startup: migrate then seed ──────────────────────────────────────────────
// postgres-js migrator is async — use a dedicated short-lived connection (max: 1)
const migrationClient = postgres(process.env.DATABASE_URL!, { max: 1 })
await migrate(drizzlePg(migrationClient), { migrationsFolder: resolve(__dirname, '../../drizzle') })
await migrationClient.end()
await seedIfEmpty()
// ────────────────────────────────────────────────────────────────────────────

const app = new Hono()

// ── Global CSRF protection ───────────────────────────────────────────────────
app.use(csrf())

/** Health check endpoint — verifies the server is running. */
app.get('/api/health', (c) => {
  return c.json({ status: 'ok', timestamp: new Date().toISOString() })
})

/** Serve the floor plan image for a specific building and floor. */
app.get('/api/floor-plan/:buildingId/:floorNumber', async (c) => {
  try {
    const buildingId = Number(c.req.param('buildingId'))
    const floorNumber = Number(c.req.param('floorNumber'))
    if (Number.isNaN(buildingId) || Number.isNaN(floorNumber)) {
      return c.json({ error: 'Invalid building or floor number' }, 400)
    }

    const [floorRow] = await db
      .select({ imagePath: floors.imagePath })
      .from(floors)
      .where(and(eq(floors.buildingId, buildingId), eq(floors.floorNumber, floorNumber)))
      .limit(1)

    if (!floorRow) return c.json({ error: 'Floor not found' }, 404)

    const buffer = await r2GetBuffer(floorRow.imagePath)
    // Detect content type from extension
    const ext = floorRow.imagePath.split('.').pop()?.toLowerCase()
    const contentType = ext === 'jpg' || ext === 'jpeg' ? 'image/jpeg' : 'image/png'
    c.header('Content-Type', contentType)
    c.header('Cache-Control', 'public, max-age=3600')
    return c.body(buffer)
  } catch (_err) {
    return c.json({ error: 'Floor plan image not found' }, 404)
  }
})

/** Serve the full-resolution floor plan PNG. */
app.get('/api/floor-plan/image', async (c) => {
  try {
    const buffer = await r2GetBuffer('floor-plan.png')
    c.header('Content-Type', 'image/png')
    c.header('Cache-Control', 'public, max-age=3600')
    return c.body(buffer)
  } catch (_err) {
    return c.json({ error: 'Floor plan not found' }, 404)
  }
})

/** Serve the low-resolution floor plan thumbnail JPEG. */
app.get('/api/floor-plan/thumbnail', async (c) => {
  try {
    const buffer = await r2GetBuffer('floor-plan-thumb.jpg')
    c.header('Content-Type', 'image/jpeg')
    c.header('Cache-Control', 'public, max-age=3600')
    return c.body(buffer)
  } catch (_err) {
    return c.json({ error: 'Floor plan thumbnail not found' }, 404)
  }
})

/** Serve the campus overhead map image. */
app.get('/api/campus/image', async (c) => {
  try {
    const [campusBuilding] = await db.select({ id: buildings.id }).from(buildings)
      .where(eq(buildings.name, 'Campus')).limit(1)
    if (!campusBuilding) return c.json({ error: 'Campus map not found' }, 404)
    const [campusFloor] = await db.select({ imagePath: floors.imagePath }).from(floors)
      .where(and(eq(floors.buildingId, campusBuilding.id), eq(floors.floorNumber, 0))).limit(1)
    if (!campusFloor) return c.json({ error: 'Campus map not found' }, 404)
    const buffer = await r2GetBuffer(campusFloor.imagePath)
    const ext = campusFloor.imagePath.split('.').pop()?.toLowerCase()
    const contentType = ext === 'jpg' || ext === 'jpeg' ? 'image/jpeg' : 'image/png'
    c.header('Content-Type', contentType)
    c.header('Cache-Control', 'public, max-age=3600')
    return c.body(buffer)
  } catch (_err) {
    return c.json({ error: 'Campus map image not found' }, 404)
  }
})

/** Serve the navigation graph as JSON — queries PostgreSQL via Drizzle. No auth required. */
app.get('/api/map', async (c) => {
  try {
    const [buildingRows, floorRows, nodeRows, edgeRows] = await Promise.all([
      db.select().from(buildings),
      db.select().from(floors),
      db.select().from(nodes),
      db.select().from(edges),
    ])

    if (buildingRows.length === 0) return c.json({ error: 'Graph data not found' }, 404)

    // Group nodes by floorId for efficient assembly
    const nodesByFloor = new Map<number, typeof nodeRows>()
    for (const n of nodeRows) {
      if (!nodesByFloor.has(n.floorId)) nodesByFloor.set(n.floorId, [])
      nodesByFloor.get(n.floorId)!.push(n)
    }

    // Assign edges to source node's floor (edges are not directly floor-scoped in DB)
    const edgesByFloor = new Map<number, typeof edgeRows>()
    const nodeFloorMap = new Map(nodeRows.map(n => [n.id, n.floorId]))
    for (const e of edgeRows) {
      const floorId = nodeFloorMap.get(e.sourceId)
      if (floorId !== undefined) {
        if (!edgesByFloor.has(floorId)) edgesByFloor.set(floorId, [])
        edgesByFloor.get(floorId)!.push(e)
      }
    }

    // Group floors by buildingId
    const floorsByBuilding = new Map<number, typeof floorRows>()
    for (const f of floorRows) {
      if (!floorsByBuilding.has(f.buildingId)) floorsByBuilding.set(f.buildingId, [])
      floorsByBuilding.get(f.buildingId)!.push(f)
    }

    const graph: NavGraph = {
      buildings: buildingRows.map((b) => ({
        id: b.id,
        name: b.name,
        floors: (floorsByBuilding.get(b.id) ?? []).map((f) => ({
          id: f.id,
          floorNumber: f.floorNumber,
          imagePath: f.imagePath,
          updatedAt: f.updatedAt,
          ...serializeFloorGpsBounds(f),
          nodes: (nodesByFloor.get(f.id) ?? []).map((n) => ({
            id: n.id,
            x: n.x,
            y: n.y,
            label: n.label,
            type: n.type as NavNode['type'],
            searchable: n.searchable,
            floorId: n.floorId,
            ...(n.roomNumber != null && { roomNumber: n.roomNumber }),
            ...(n.description != null && { description: n.description }),
            ...(n.accessibilityNotes != null && { accessibilityNotes: n.accessibilityNotes }),
            ...(n.connectsToFloorAboveId != null && { connectsToFloorAboveId: n.connectsToFloorAboveId }),
            ...(n.connectsToFloorBelowId != null && { connectsToFloorBelowId: n.connectsToFloorBelowId }),
            ...(n.connectsToNodeAboveId != null && { connectsToNodeAboveId: n.connectsToNodeAboveId }),
            ...(n.connectsToNodeBelowId != null && { connectsToNodeBelowId: n.connectsToNodeBelowId }),
            ...(n.connectsToBuildingId != null && { connectsToBuildingId: n.connectsToBuildingId }),
          })),
          edges: (edgesByFloor.get(f.id) ?? []).map((e) => ({
            id: e.id,
            sourceId: e.sourceId,
            targetId: e.targetId,
            standardWeight: e.standardWeight,
            accessibleWeight: e.accessibleWeight,
            accessible: e.accessible,
            bidirectional: e.bidirectional,
            ...(e.accessibilityNotes != null && { accessibilityNotes: e.accessibilityNotes }),
          })),
        })),
      })),
    }

    c.header('Cache-Control', 'public, max-age=60')
    return c.json(graph)
  } catch (_err) {
    return c.json({ error: 'Failed to load graph data' }, 500)
  }
})

// ── Auth routes (public — login/logout/me) ────────────────────────────────────
app.route('/api/auth', authRoutes)

// ── JWT guard for all admin API routes ────────────────────────────────────────
app.use('/api/admin/*', jwt({ secret: JWT_SECRET, alg: 'HS256', cookie: 'admin_token' }))

// ── Admin routes (protected) ──────────────────────────────────────────────────

/**
 * POST /api/admin/connectors/link
 * Links, relinks, or unlinks connector nodes (`stairs`/`elevator`/`ramp`) atomically.
 * Request body: { sourceNodeId, direction: "above"|"below", targetNodeId?: string|null }
 */
app.post('/api/admin/connectors/link', async (c) => {
  try {
    let body: unknown

    try {
      body = await c.req.json()
    } catch {
      return c.json({ errorCode: 'INVALID_REQUEST', error: 'Request body must be valid JSON' }, 400)
    }

    const result = await linkConnectorNodesFromPayload(body)
    return c.json(result)
  } catch (error) {
    if (error instanceof ConnectorLinkingError) {
      return c.json({ errorCode: error.code, error: error.message }, error.status)
    }

    console.error('Connector link update failed:', error)
    return c.json({ errorCode: 'INTERNAL_ERROR', error: 'Failed to update connector link' }, 500)
  }
})

/**
 * POST /api/admin/graph
 * Replaces the entire navigation graph in PostgreSQL atomically.
 * Receives a full NavGraph JSON body (buildings → floors → nodes/edges);
 * wraps delete+insert in a PostgreSQL transaction.
 */
app.post('/api/admin/graph', async (c) => {
  try {
    const graph = (await c.req.json()) as NavGraph
    // Basic validation: must have buildings array
    if (!Array.isArray(graph.buildings)) {
      return c.json({ error: 'Invalid graph data' }, 400)
    }

    await db.transaction(async (tx) => {
      // Delete in FK-safe order (edges → nodes → floors → buildings)
      await tx.delete(edges)
      await tx.delete(nodes)
      await tx.delete(floors)
      await tx.delete(buildings)

      for (const b of graph.buildings) {
        const buildingRows = await tx.insert(buildings).values({ name: b.name }).returning({ id: buildings.id })
        if (buildingRows.length === 0) throw new Error('Failed to insert building')
        const building = buildingRows[0]!

        for (const f of b.floors) {
          const floorRows = await tx.insert(floors).values({
            buildingId: building.id,
            floorNumber: f.floorNumber,
            imagePath: f.imagePath,
            updatedAt: new Date().toISOString(),
          }).returning({ id: floors.id })
          if (floorRows.length === 0) throw new Error('Failed to insert floor')
          const floor = floorRows[0]!

          for (const n of f.nodes) {
            await tx.insert(nodes).values({
              id: n.id, x: n.x, y: n.y, label: n.label, type: n.type,
              searchable: n.searchable, floorId: floor.id,
              roomNumber: n.roomNumber ?? null,
              description: n.description ?? null,
              accessibilityNotes: n.accessibilityNotes ?? null,
              connectsToFloorAboveId: n.connectsToFloorAboveId ?? null,
              connectsToFloorBelowId: n.connectsToFloorBelowId ?? null,
              connectsToNodeAboveId: n.connectsToNodeAboveId ?? null,
              connectsToNodeBelowId: n.connectsToNodeBelowId ?? null,
              connectsToBuildingId: n.connectsToBuildingId ?? null,
            })
          }

          for (const e of f.edges) {
            await tx.insert(edges).values({
              id: e.id, sourceId: e.sourceId, targetId: e.targetId,
              standardWeight: e.standardWeight, accessibleWeight: e.accessibleWeight,
              accessible: e.accessible, bidirectional: e.bidirectional,
              accessibilityNotes: e.accessibilityNotes ?? null,
            })
          }
        }
      }
    })

    return c.json({ ok: true })
  } catch (err) {
    console.error('Graph save failed:', err)
    return c.json({ error: 'Failed to save graph' }, 500)
  }
})

/**
 * POST /api/admin/floor-plan
 * Accepts a multipart image upload and writes it to the server assets directory.
 * The uploaded image replaces the existing floor-plan.png.
 */
app.post('/api/admin/floor-plan', async (c) => {
  try {
    const body = await c.req.parseBody()
    const file = body.image
    if (!file || !(file instanceof File)) {
      return c.json({ error: 'No image file provided' }, 400)
    }
    if (!file.type.startsWith('image/')) {
      return c.json({ error: 'File must be an image' }, 400)
    }
    const buffer = Buffer.from(await file.arrayBuffer())
    await r2PutBuffer('floor-plan.png', buffer, file.type)
    return c.json({ ok: true })
  } catch (err) {
    console.error('Floor plan upload failed:', err)
    return c.json({ error: 'Failed to upload floor plan' }, 500)
  }
})

/**
 * POST /api/admin/floors
 * Accepts multipart form with buildingId, floorNumber, image.
 * Creates the floor record and saves the image atomically.
 */
app.post('/api/admin/floors', async (c) => {
  try {
    const body = await c.req.parseBody()
    const buildingId = Number(body.buildingId)
    const floorNumber = Number(body.floorNumber)
    const file = body.image
    if (Number.isNaN(buildingId) || Number.isNaN(floorNumber)) {
      return c.json({ error: 'Invalid buildingId or floorNumber' }, 400)
    }
    if (!file || !(file instanceof File)) return c.json({ error: 'No image file provided' }, 400)
    if (!file.type.startsWith('image/')) return c.json({ error: 'File must be an image' }, 400)
    const ext = file.name.split('.').pop()?.toLowerCase() ?? 'png'
    const filename = `floor-plan-${buildingId}-${floorNumber}.${ext}`
    const buffer = Buffer.from(await file.arrayBuffer())
    await r2PutBuffer(filename, buffer, file.type)
    const floorRows = await db.insert(floors).values({
      buildingId,
      floorNumber,
      imagePath: filename,
      updatedAt: new Date().toISOString(),
    }).returning({ id: floors.id })
    if (floorRows.length === 0) throw new Error('Failed to insert floor')
    return c.json({ ok: true, floorId: floorRows[0]!.id })
  } catch (err) {
    console.error('Add floor failed:', err)
    return c.json({ error: 'Failed to add floor' }, 500)
  }
})

/**
 * DELETE /api/admin/floors/:id
 * Deletes the floor and all its nodes + edges in FK-safe order
 * (edges first, then nodes, then floor).
 */
app.delete('/api/admin/floors/:id', async (c) => {
  try {
    const floorId = Number(c.req.param('id'))
    if (Number.isNaN(floorId)) return c.json({ error: 'Invalid floor id' }, 400)
    await db.transaction(async (tx) => {
      const floorNodeIds = await tx.select({ id: nodes.id }).from(nodes).where(eq(nodes.floorId, floorId))
      const ids = floorNodeIds.map(n => n.id)
      if (ids.length > 0) {
        await tx.delete(edges).where(inArray(edges.sourceId, ids))
        await tx.delete(edges).where(inArray(edges.targetId, ids))
        await tx.delete(nodes).where(eq(nodes.floorId, floorId))
      }
      await tx.delete(floors).where(eq(floors.id, floorId))
    })
    return c.json({ ok: true })
  } catch (err) {
    console.error('Delete floor failed:', err)
    return c.json({ error: 'Failed to delete floor' }, 500)
  }
})

/**
 * POST /api/admin/floor-plan/:buildingId/:floorNumber
 * Replaces the image for an existing floor. Saves file as
 * floor-plan-{buildingId}-{floorNumber}.{ext} and updates floors.imagePath.
 */
app.post('/api/admin/floor-plan/:buildingId/:floorNumber', async (c) => {
  try {
    const buildingId = Number(c.req.param('buildingId'))
    const floorNumber = Number(c.req.param('floorNumber'))
    if (Number.isNaN(buildingId) || Number.isNaN(floorNumber)) {
      return c.json({ error: 'Invalid building or floor number' }, 400)
    }
    const body = await c.req.parseBody()
    const file = body.image
    if (!file || !(file instanceof File)) return c.json({ error: 'No image file provided' }, 400)
    if (!file.type.startsWith('image/')) return c.json({ error: 'File must be an image' }, 400)
    const ext = file.name.split('.').pop()?.toLowerCase() ?? 'png'
    const filename = `floor-plan-${buildingId}-${floorNumber}.${ext}`
    const buffer = Buffer.from(await file.arrayBuffer())
    await r2PutBuffer(filename, buffer, file.type)
    await db.update(floors)
      .set({ imagePath: filename, updatedAt: new Date().toISOString() })
      .where(and(eq(floors.buildingId, buildingId), eq(floors.floorNumber, floorNumber)))
    return c.json({ ok: true })
  } catch (err) {
    console.error('Replace floor image failed:', err)
    return c.json({ error: 'Failed to replace floor image' }, 500)
  }
})

/**
 * POST /api/admin/campus/image
 * Upsert pattern — creates Campus building+floor if they don't exist,
 * then saves the campus-map.{ext} image.
 */
app.post('/api/admin/campus/image', async (c) => {
  try {
    const body = await c.req.parseBody()
    const file = body.image
    if (!file || !(file instanceof File)) return c.json({ error: 'No image file provided' }, 400)
    if (!file.type.startsWith('image/')) return c.json({ error: 'File must be an image' }, 400)
    const ext = file.name.split('.').pop()?.toLowerCase() ?? 'png'
    const filename = `campus-map.${ext}`
    const buffer = Buffer.from(await file.arrayBuffer())
    await r2PutBuffer(filename, buffer, file.type)
    // Upsert Campus building
    let [campusBuilding] = await db.select({ id: buildings.id }).from(buildings)
      .where(eq(buildings.name, 'Campus')).limit(1)
    if (!campusBuilding) {
      const rows = await db.insert(buildings).values({ name: 'Campus' }).returning({ id: buildings.id })
      if (rows.length === 0) throw new Error('Failed to create Campus building')
      campusBuilding = rows[0]!
    }
    // Upsert Campus floor (floorNumber = 0 is the sentinel)
    let [campusFloor] = await db.select({ id: floors.id }).from(floors)
      .where(and(eq(floors.buildingId, campusBuilding.id), eq(floors.floorNumber, 0))).limit(1)
    if (!campusFloor) {
      const rows = await db.insert(floors).values({
        buildingId: campusBuilding.id,
        floorNumber: 0,
        imagePath: filename,
        updatedAt: new Date().toISOString(),
      }).returning({ id: floors.id })
      if (rows.length === 0) throw new Error('Failed to create Campus floor')
      campusFloor = rows[0]!
    } else {
      await db.update(floors)
        .set({ imagePath: filename, updatedAt: new Date().toISOString() })
        .where(eq(floors.id, campusFloor.id))
    }
    return c.json({ ok: true, buildingId: campusBuilding.id, floorId: campusFloor.id })
  } catch (err) {
    console.error('Campus image upload failed:', err)
    return c.json({ error: 'Failed to upload campus image' }, 500)
  }
})

app.use('/*', serveStatic({ root: './dist/client' }))

app.get('/*', async (c) => {
  const html = await readFile('./dist/client/index.html', 'utf-8')
  return c.html(html)
})

const port = Number(process.env.PORT) || 3001
console.log(`Server running on http://localhost:${port}`)
serve({ fetch: app.fetch, port })

import { describe, expect, it } from 'vitest'
import { serializeFloorGpsBounds, toNavFloorGpsBounds } from './floorGpsBounds'

describe('serializeFloorGpsBounds', () => {
  it('serializes gpsBounds only when complete tuple is present', () => {
    expect(
      serializeFloorGpsBounds({
        gpsMinLat: 14.5811,
        gpsMaxLat: 14.5822,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      }),
    ).toEqual({
      gpsBounds: {
        minLat: 14.5811,
        maxLat: 14.5822,
        minLng: 121.0412,
        maxLng: 121.0423,
      },
    })

    expect(
      serializeFloorGpsBounds({
        gpsMinLat: 14.5811,
        gpsMaxLat: 14.5822,
        gpsMinLng: null,
        gpsMaxLng: 121.0423,
      }),
    ).toEqual({})

    expect(
      serializeFloorGpsBounds({
        gpsMinLat: null,
        gpsMaxLat: null,
        gpsMinLng: null,
        gpsMaxLng: null,
      }),
    ).toEqual({})
  })
})

describe('toNavFloorGpsBounds', () => {
  it('returns null when one or more tuple values are missing', () => {
    expect(
      toNavFloorGpsBounds({
        gpsMinLat: 14.5811,
        gpsMaxLat: null,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      }),
    ).toBeNull()
  })

  it('returns null when tuple contains non-finite values', () => {
    expect(
      toNavFloorGpsBounds({
        gpsMinLat: Number.NaN,
        gpsMaxLat: 14.5822,
        gpsMinLng: 121.0412,
        gpsMaxLng: 121.0423,
      }),
    ).toBeNull()
  })
})

import type { NavNodeType } from '@shared/types'
import { eq } from 'drizzle-orm'
import { db } from './db/client'
import { floors, nodes } from './db/schema'

export type ConnectorDirection = 'above' | 'below'

type NodeConnectorField = 'connectsToNodeAboveId' | 'connectsToNodeBelowId'
type FloorConnectorField = 'connectsToFloorAboveId' | 'connectsToFloorBelowId'

type ConnectorNodeType = Extract<NavNodeType, 'stairs' | 'elevator' | 'ramp'>

const CONNECTOR_NODE_TYPES = new Set<ConnectorNodeType>(['stairs', 'elevator', 'ramp'])

export type ConnectorLinkErrorCode =
  | 'INVALID_REQUEST'
  | 'SOURCE_NOT_FOUND'
  | 'TARGET_NOT_FOUND'
  | 'SOURCE_NOT_CONNECTOR'
  | 'TARGET_NOT_CONNECTOR'
  | 'LINK_VALIDATION_ERROR'

type ConnectorLinkErrorStatus = 400 | 404

const CONNECTOR_LINK_ERROR_STATUS = {
  INVALID_REQUEST: 400,
  SOURCE_NOT_FOUND: 404,
  TARGET_NOT_FOUND: 404,
  SOURCE_NOT_CONNECTOR: 400,
  TARGET_NOT_CONNECTOR: 400,
  LINK_VALIDATION_ERROR: 400,
} as const satisfies Record<ConnectorLinkErrorCode, ConnectorLinkErrorStatus>

export class ConnectorLinkingError extends Error {
  readonly code: ConnectorLinkErrorCode
  readonly status: ConnectorLinkErrorStatus

  constructor(code: ConnectorLinkErrorCode, message: string) {
    super(message)
    this.name = 'ConnectorLinkingError'
    this.code = code
    this.status = CONNECTOR_LINK_ERROR_STATUS[code]
  }
}

export interface ConnectorLinkRequest {
  sourceNodeId: string
  direction: ConnectorDirection
  targetNodeId: string | null
}

export interface ConnectorNodeUpdate {
  id: string
  floorId: number
  connectsToFloorAboveId: number | null
  connectsToFloorBelowId: number | null
  connectsToNodeAboveId: string | null
  connectsToNodeBelowId: string | null
}

export interface ConnectorLinkResult {
  ok: true
  updatedNodes: ConnectorNodeUpdate[]
}

export interface ConnectorNodeRecord extends ConnectorNodeUpdate {
  type: string
}

export interface ConnectorFloorRecord {
  id: number
  buildingId: number
  floorNumber: number
}

type ConnectorNodePatch = Partial<Pick<
  ConnectorNodeUpdate,
  | 'connectsToFloorAboveId'
  | 'connectsToFloorBelowId'
  | 'connectsToNodeAboveId'
  | 'connectsToNodeBelowId'
>>

interface DirectionSpec {
  sourceNodeField: NodeConnectorField
  sourceFloorField: FloorConnectorField
  counterpartNodeField: NodeConnectorField
  counterpartFloorField: FloorConnectorField
}

export interface ConnectorLinkStoreTx {
  getNodeById(nodeId: string): Promise<ConnectorNodeRecord | null>
  getFloorById(floorId: number): Promise<ConnectorFloorRecord | null>
  updateNodeById(nodeId: string, patch: ConnectorNodePatch): Promise<ConnectorNodeUpdate>
}

export interface ConnectorLinkStore {
  transaction<T>(callback: (tx: ConnectorLinkStoreTx) => Promise<T>): Promise<T>
}

type DrizzleConnectorTx = Pick<typeof db, 'select' | 'update'>

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null
}

function isConnectorNodeType(nodeType: string): nodeType is ConnectorNodeType {
  return CONNECTOR_NODE_TYPES.has(nodeType as ConnectorNodeType)
}

function directionSpec(direction: ConnectorDirection): DirectionSpec {
  if (direction === 'above') {
    return {
      sourceNodeField: 'connectsToNodeAboveId',
      sourceFloorField: 'connectsToFloorAboveId',
      counterpartNodeField: 'connectsToNodeBelowId',
      counterpartFloorField: 'connectsToFloorBelowId',
    }
  }

  return {
    sourceNodeField: 'connectsToNodeBelowId',
    sourceFloorField: 'connectsToFloorBelowId',
    counterpartNodeField: 'connectsToNodeAboveId',
    counterpartFloorField: 'connectsToFloorAboveId',
  }
}

function getRequiredStringField(
  body: Record<string, unknown>,
  fieldName: string,
): string {
  const rawValue = body[fieldName]
  if (typeof rawValue !== 'string') {
    throw new ConnectorLinkingError('INVALID_REQUEST', `${fieldName} must be a string`)
  }

  const value = rawValue.trim()
  if (value.length === 0) {
    throw new ConnectorLinkingError('INVALID_REQUEST', `${fieldName} is required`)
  }

  return value
}

function getTargetNodeId(body: Record<string, unknown>): string | null {
  if (!Object.hasOwn(body, 'targetNodeId')) {
    return null
  }

  const rawValue = body.targetNodeId
  if (rawValue === null || rawValue === undefined) {
    return null
  }

  if (typeof rawValue !== 'string') {
    throw new ConnectorLinkingError('INVALID_REQUEST', 'targetNodeId must be a string or null')
  }

  const value = rawValue.trim()
  return value.length === 0 ? null : value
}

export function parseConnectorLinkRequest(payload: unknown): ConnectorLinkRequest {
  if (!isRecord(payload)) {
    throw new ConnectorLinkingError('INVALID_REQUEST', 'Request body must be a JSON object')
  }

  const sourceNodeId = getRequiredStringField(payload, 'sourceNodeId')
  const directionRaw = getRequiredStringField(payload, 'direction')

  if (directionRaw !== 'above' && directionRaw !== 'below') {
    throw new ConnectorLinkingError('INVALID_REQUEST', 'direction must be "above" or "below"')
  }

  return {
    sourceNodeId,
    direction: directionRaw,
    targetNodeId: getTargetNodeId(payload),
  }
}

function createDrizzleStoreTx(tx: DrizzleConnectorTx): ConnectorLinkStoreTx {
  return {
    async getNodeById(nodeId) {
      const [row] = await tx
        .select({
          id: nodes.id,
          type: nodes.type,
          floorId: nodes.floorId,
          connectsToFloorAboveId: nodes.connectsToFloorAboveId,
          connectsToFloorBelowId: nodes.connectsToFloorBelowId,
          connectsToNodeAboveId: nodes.connectsToNodeAboveId,
          connectsToNodeBelowId: nodes.connectsToNodeBelowId,
        })
        .from(nodes)
        .where(eq(nodes.id, nodeId))
        .limit(1)

      return row ?? null
    },

    async getFloorById(floorId) {
      const [row] = await tx
        .select({ id: floors.id, buildingId: floors.buildingId, floorNumber: floors.floorNumber })
        .from(floors)
        .where(eq(floors.id, floorId))
        .limit(1)

      return row ?? null
    },

    async updateNodeById(nodeId, patch) {
      const [updatedRow] = await tx
        .update(nodes)
        .set(patch)
        .where(eq(nodes.id, nodeId))
        .returning({
          id: nodes.id,
          floorId: nodes.floorId,
          connectsToFloorAboveId: nodes.connectsToFloorAboveId,
          connectsToFloorBelowId: nodes.connectsToFloorBelowId,
          connectsToNodeAboveId: nodes.connectsToNodeAboveId,
          connectsToNodeBelowId: nodes.connectsToNodeBelowId,
        })

      if (!updatedRow) {
        throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', `Node ${nodeId} no longer exists`)
      }

      return updatedRow
    },
  }
}

const drizzleConnectorStore: ConnectorLinkStore = {
  transaction(callback) {
    return db.transaction(async (tx) => callback(createDrizzleStoreTx(tx)))
  },
}

function createDirectionalPatch(
  nodeField: NodeConnectorField,
  nodeId: string | null,
  floorField: FloorConnectorField,
  floorId: number | null,
): ConnectorNodePatch {
  return {
    [nodeField]: nodeId,
    [floorField]: floorId,
  } as ConnectorNodePatch
}

function mergePatch(
  patchMap: Map<string, ConnectorNodePatch>,
  nodeId: string,
  patch: ConnectorNodePatch,
): void {
  const existing = patchMap.get(nodeId)
  if (!existing) {
    patchMap.set(nodeId, patch)
    return
  }

  patchMap.set(nodeId, { ...existing, ...patch })
}

async function applyPatches(
  tx: ConnectorLinkStoreTx,
  patchMap: Map<string, ConnectorNodePatch>,
): Promise<ConnectorNodeUpdate[]> {
  const updatedNodes: ConnectorNodeUpdate[] = []

  for (const [nodeId, patch] of patchMap) {
    updatedNodes.push(await tx.updateNodeById(nodeId, patch))
  }

  updatedNodes.sort((a, b) => a.id.localeCompare(b.id))
  return updatedNodes
}

function validateFloorDirection(
  sourceFloor: ConnectorFloorRecord,
  targetFloor: ConnectorFloorRecord,
  direction: ConnectorDirection,
): void {
  if (sourceFloor.buildingId !== targetFloor.buildingId) {
    throw new ConnectorLinkingError(
      'LINK_VALIDATION_ERROR',
      'Source and target connectors must be in the same building',
    )
  }

  const floorDelta = targetFloor.floorNumber - sourceFloor.floorNumber

  if (floorDelta === 0) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Source and target cannot be on the same floor')
  }

  if (Math.abs(floorDelta) !== 1) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Connector links must target an adjacent floor')
  }

  if (direction === 'above' && floorDelta <= 0) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Direction "above" requires a higher floor target')
  }

  if (direction === 'below' && floorDelta >= 0) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Direction "below" requires a lower floor target')
  }
}

async function clearReciprocalIfLinked(
  tx: ConnectorLinkStoreTx,
  patchMap: Map<string, ConnectorNodePatch>,
  counterpartNodeId: string,
  counterpartNodeField: NodeConnectorField,
  counterpartFloorField: FloorConnectorField,
  expectedLinkedNodeId: string,
): Promise<void> {
  const counterpartNode = await tx.getNodeById(counterpartNodeId)
  if (!counterpartNode) return

  if (counterpartNode[counterpartNodeField] !== expectedLinkedNodeId) {
    return
  }

  mergePatch(
    patchMap,
    counterpartNode.id,
    createDirectionalPatch(counterpartNodeField, null, counterpartFloorField, null),
  )
}

async function unlinkConnectorDirection(
  tx: ConnectorLinkStoreTx,
  sourceNode: ConnectorNodeRecord,
  spec: DirectionSpec,
): Promise<ConnectorLinkResult> {
  const patchMap = new Map<string, ConnectorNodePatch>()

  mergePatch(
    patchMap,
    sourceNode.id,
    createDirectionalPatch(spec.sourceNodeField, null, spec.sourceFloorField, null),
  )

  const previousCounterpartId = sourceNode[spec.sourceNodeField]
  if (previousCounterpartId) {
    await clearReciprocalIfLinked(
      tx,
      patchMap,
      previousCounterpartId,
      spec.counterpartNodeField,
      spec.counterpartFloorField,
      sourceNode.id,
    )
  }

  const updatedNodes = await applyPatches(tx, patchMap)
  return { ok: true, updatedNodes }
}

async function linkConnectorDirection(
  tx: ConnectorLinkStoreTx,
  sourceNode: ConnectorNodeRecord,
  sourceFloor: ConnectorFloorRecord,
  targetNode: ConnectorNodeRecord,
  targetFloor: ConnectorFloorRecord,
  spec: DirectionSpec,
): Promise<ConnectorLinkResult> {
  const patchMap = new Map<string, ConnectorNodePatch>()

  const sourcePreviousCounterpartId = sourceNode[spec.sourceNodeField]
  if (sourcePreviousCounterpartId && sourcePreviousCounterpartId !== targetNode.id) {
    await clearReciprocalIfLinked(
      tx,
      patchMap,
      sourcePreviousCounterpartId,
      spec.counterpartNodeField,
      spec.counterpartFloorField,
      sourceNode.id,
    )
  }

  const targetPreviousCounterpartId = targetNode[spec.counterpartNodeField]
  if (targetPreviousCounterpartId && targetPreviousCounterpartId !== sourceNode.id) {
    await clearReciprocalIfLinked(
      tx,
      patchMap,
      targetPreviousCounterpartId,
      spec.sourceNodeField,
      spec.sourceFloorField,
      targetNode.id,
    )
  }

  mergePatch(
    patchMap,
    sourceNode.id,
    createDirectionalPatch(spec.sourceNodeField, targetNode.id, spec.sourceFloorField, targetFloor.id),
  )

  mergePatch(
    patchMap,
    targetNode.id,
    createDirectionalPatch(spec.counterpartNodeField, sourceNode.id, spec.counterpartFloorField, sourceFloor.id),
  )

  const updatedNodes = await applyPatches(tx, patchMap)
  return { ok: true, updatedNodes }
}

async function executeConnectorLink(
  tx: ConnectorLinkStoreTx,
  request: ConnectorLinkRequest,
): Promise<ConnectorLinkResult> {
  const sourceNode = await tx.getNodeById(request.sourceNodeId)
  if (!sourceNode) {
    throw new ConnectorLinkingError('SOURCE_NOT_FOUND', `Source node ${request.sourceNodeId} was not found`)
  }

  if (!isConnectorNodeType(sourceNode.type)) {
    throw new ConnectorLinkingError('SOURCE_NOT_CONNECTOR', 'Source node must be stairs, elevator, or ramp')
  }

  const sourceFloor = await tx.getFloorById(sourceNode.floorId)
  if (!sourceFloor) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Source node floor could not be resolved')
  }

  const spec = directionSpec(request.direction)

  if (request.targetNodeId === null) {
    return unlinkConnectorDirection(tx, sourceNode, spec)
  }

  if (request.targetNodeId === sourceNode.id) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Source node cannot link to itself')
  }

  const targetNode = await tx.getNodeById(request.targetNodeId)
  if (!targetNode) {
    throw new ConnectorLinkingError('TARGET_NOT_FOUND', `Target node ${request.targetNodeId} was not found`)
  }

  if (!isConnectorNodeType(targetNode.type)) {
    throw new ConnectorLinkingError('TARGET_NOT_CONNECTOR', 'Target node must be stairs, elevator, or ramp')
  }

  const targetFloor = await tx.getFloorById(targetNode.floorId)
  if (!targetFloor) {
    throw new ConnectorLinkingError('LINK_VALIDATION_ERROR', 'Target node floor could not be resolved')
  }

  validateFloorDirection(sourceFloor, targetFloor, request.direction)

  return linkConnectorDirection(tx, sourceNode, sourceFloor, targetNode, targetFloor, spec)
}

export async function linkConnectorNodes(
  request: ConnectorLinkRequest,
  options?: { store?: ConnectorLinkStore },
): Promise<ConnectorLinkResult> {
  const store = options?.store ?? drizzleConnectorStore
  return store.transaction(async (tx) => executeConnectorLink(tx, request))
}

export async function linkConnectorNodesFromPayload(
  payload: unknown,
  options?: { store?: ConnectorLinkStore },
): Promise<ConnectorLinkResult> {
  const request = parseConnectorLinkRequest(payload)
  return linkConnectorNodes(request, options)
}

import { describe, expect, it } from 'vitest'
import {
  type ConnectorFloorRecord,
  type ConnectorLinkStore,
  type ConnectorLinkStoreTx,
  type ConnectorNodeRecord,
  ConnectorLinkingError,
  linkConnectorNodes,
} from './connectorLinking'

interface InMemoryStore {
  store: ConnectorLinkStore
  getNode(nodeId: string): ConnectorNodeRecord | null
  snapshotNodes(): ConnectorNodeRecord[]
}

const DEFAULT_FLOORS: ConnectorFloorRecord[] = [
  { id: 101, buildingId: 1, floorNumber: 1 },
  { id: 102, buildingId: 1, floorNumber: 2 },
  { id: 103, buildingId: 1, floorNumber: 3 },
  { id: 201, buildingId: 2, floorNumber: 2 },
]

function makeNode(
  id: string,
  floorId: number,
  type: ConnectorNodeRecord['type'] = 'stairs',
  overrides: Partial<ConnectorNodeRecord> = {},
): ConnectorNodeRecord {
  return {
    id,
    type,
    floorId,
    connectsToFloorAboveId: null,
    connectsToFloorBelowId: null,
    connectsToNodeAboveId: null,
    connectsToNodeBelowId: null,
    ...overrides,
  }
}

function cloneNode(node: ConnectorNodeRecord): ConnectorNodeRecord {
  return { ...node }
}

function createInMemoryStore(options: {
  nodes: ConnectorNodeRecord[]
  floors?: ConnectorFloorRecord[]
}): InMemoryStore {
  const floorMap = new Map(
    (options.floors ?? DEFAULT_FLOORS).map((floor) => [floor.id, { ...floor }]),
  )

  let committedNodes = new Map(
    options.nodes.map((node) => [node.id, cloneNode(node)]),
  )

  const buildTransaction = (
    workingNodes: Map<string, ConnectorNodeRecord>,
  ): ConnectorLinkStoreTx => ({
    async getNodeById(nodeId) {
      const node = workingNodes.get(nodeId)
      return node ? cloneNode(node) : null
    },

    async getFloorById(floorId) {
      const floor = floorMap.get(floorId)
      return floor ? { ...floor } : null
    },

    async updateNodeById(nodeId, patch) {
      const current = workingNodes.get(nodeId)
      if (!current) {
        throw new Error(`Unknown node ${nodeId}`)
      }

      const next = { ...current, ...patch }
      workingNodes.set(nodeId, next)

      return {
        id: next.id,
        floorId: next.floorId,
        connectsToFloorAboveId: next.connectsToFloorAboveId,
        connectsToFloorBelowId: next.connectsToFloorBelowId,
        connectsToNodeAboveId: next.connectsToNodeAboveId,
        connectsToNodeBelowId: next.connectsToNodeBelowId,
      }
    },
  })

  const store: ConnectorLinkStore = {
    async transaction(callback) {
      const workingNodes = new Map(
        Array.from(committedNodes.entries()).map(([id, node]) => [id, cloneNode(node)]),
      )

      try {
        const result = await callback(buildTransaction(workingNodes))
        committedNodes = workingNodes
        return result
      } catch (error) {
        throw error
      }
    },
  }

  return {
    store,
    getNode(nodeId) {
      const node = committedNodes.get(nodeId)
      return node ? cloneNode(node) : null
    },
    snapshotNodes() {
      return Array.from(committedNodes.values())
        .map((node) => cloneNode(node))
        .sort((left, right) => left.id.localeCompare(right.id))
    },
  }
}

describe('linkConnectorNodes', () => {
  it('links source and target connectors atomically', async () => {
    const source = makeNode('stairs-f1-a', 101)
    const target = makeNode('stairs-f2-a', 102)
    const memory = createInMemoryStore({ nodes: [source, target] })

    const result = await linkConnectorNodes(
      {
        sourceNodeId: source.id,
        direction: 'above',
        targetNodeId: target.id,
      },
      { store: memory.store },
    )

    expect(result.ok).toBe(true)
    expect(result.updatedNodes).toHaveLength(2)

    expect(memory.getNode(source.id)).toMatchObject({
      connectsToNodeAboveId: target.id,
      connectsToFloorAboveId: 102,
      connectsToNodeBelowId: null,
      connectsToFloorBelowId: null,
    })

    expect(memory.getNode(target.id)).toMatchObject({
      connectsToNodeBelowId: source.id,
      connectsToFloorBelowId: 101,
      connectsToNodeAboveId: null,
      connectsToFloorAboveId: null,
    })
  })

  it('relinks and clears stale reciprocal links for both displaced connectors', async () => {
    const source = makeNode('stairs-f1-source', 101, 'stairs', {
      connectsToNodeAboveId: 'stairs-f2-old',
      connectsToFloorAboveId: 102,
    })
    const oldTarget = makeNode('stairs-f2-old', 102, 'stairs', {
      connectsToNodeBelowId: source.id,
      connectsToFloorBelowId: 101,
    })

    const newTarget = makeNode('stairs-f2-new', 102, 'stairs', {
      connectsToNodeBelowId: 'stairs-f1-displaced',
      connectsToFloorBelowId: 101,
    })

    const displacedSource = makeNode('stairs-f1-displaced', 101, 'stairs', {
      connectsToNodeAboveId: newTarget.id,
      connectsToFloorAboveId: 102,
    })

    const memory = createInMemoryStore({
      nodes: [source, oldTarget, newTarget, displacedSource],
    })

    const result = await linkConnectorNodes(
      {
        sourceNodeId: source.id,
        direction: 'above',
        targetNodeId: newTarget.id,
      },
      { store: memory.store },
    )

    expect(result.ok).toBe(true)
    expect(result.updatedNodes).toHaveLength(4)

    expect(memory.getNode(source.id)).toMatchObject({
      connectsToNodeAboveId: newTarget.id,
      connectsToFloorAboveId: 102,
    })

    expect(memory.getNode(newTarget.id)).toMatchObject({
      connectsToNodeBelowId: source.id,
      connectsToFloorBelowId: 101,
    })

    expect(memory.getNode(oldTarget.id)).toMatchObject({
      connectsToNodeBelowId: null,
      connectsToFloorBelowId: null,
    })

    expect(memory.getNode(displacedSource.id)).toMatchObject({
      connectsToNodeAboveId: null,
      connectsToFloorAboveId: null,
    })
  })

  it('unlinks and clears both sides of an existing connector pair', async () => {
    const source = makeNode('stairs-f1-unlink', 101, 'stairs', {
      connectsToNodeAboveId: 'stairs-f2-unlink',
      connectsToFloorAboveId: 102,
    })

    const target = makeNode('stairs-f2-unlink', 102, 'stairs', {
      connectsToNodeBelowId: source.id,
      connectsToFloorBelowId: 101,
    })

    const memory = createInMemoryStore({ nodes: [source, target] })

    const result = await linkConnectorNodes(
      {
        sourceNodeId: source.id,
        direction: 'above',
        targetNodeId: null,
      },
      { store: memory.store },
    )

    expect(result.ok).toBe(true)
    expect(result.updatedNodes).toHaveLength(2)

    expect(memory.getNode(source.id)).toMatchObject({
      connectsToNodeAboveId: null,
      connectsToFloorAboveId: null,
    })

    expect(memory.getNode(target.id)).toMatchObject({
      connectsToNodeBelowId: null,
      connectsToFloorBelowId: null,
    })
  })

  it('returns LINK_VALIDATION_ERROR when direction/floor pairing is invalid', async () => {
    const source = makeNode('stairs-f2-direction', 102)
    const target = makeNode('stairs-f1-direction', 101)
    const memory = createInMemoryStore({ nodes: [source, target] })
    const before = memory.snapshotNodes()

    await expect(
      linkConnectorNodes(
        {
          sourceNodeId: source.id,
          direction: 'above',
          targetNodeId: target.id,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<ConnectorLinkingError>>({
      code: 'LINK_VALIDATION_ERROR',
    })

    expect(memory.snapshotNodes()).toEqual(before)
  })

  it('rejects same-floor links and leaves state unchanged', async () => {
    const source = makeNode('stairs-f1-same-floor-source', 101)
    const target = makeNode('stairs-f1-same-floor-target', 101)
    const memory = createInMemoryStore({ nodes: [source, target] })
    const before = memory.snapshotNodes()

    await expect(
      linkConnectorNodes(
        {
          sourceNodeId: source.id,
          direction: 'above',
          targetNodeId: target.id,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<ConnectorLinkingError>>({
      code: 'LINK_VALIDATION_ERROR',
    })

    expect(memory.snapshotNodes()).toEqual(before)
  })

  it('rejects cross-building links and leaves state unchanged', async () => {
    const source = makeNode('stairs-building-a', 101)
    const target = makeNode('stairs-building-b', 201)
    const memory = createInMemoryStore({ nodes: [source, target] })
    const before = memory.snapshotNodes()

    await expect(
      linkConnectorNodes(
        {
          sourceNodeId: source.id,
          direction: 'above',
          targetNodeId: target.id,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<ConnectorLinkingError>>({
      code: 'LINK_VALIDATION_ERROR',
    })

    expect(memory.snapshotNodes()).toEqual(before)
  })

  it('rejects non-connector target nodes and leaves state unchanged', async () => {
    const source = makeNode('stairs-f1', 101)
    const target = makeNode('room-f2', 102, 'room')
    const memory = createInMemoryStore({ nodes: [source, target] })
    const before = memory.snapshotNodes()

    await expect(
      linkConnectorNodes(
        {
          sourceNodeId: source.id,
          direction: 'above',
          targetNodeId: target.id,
        },
        { store: memory.store },
      ),
    ).rejects.toMatchObject<Partial<ConnectorLinkingError>>({
      code: 'TARGET_NOT_CONNECTOR',
    })

    expect(memory.snapshotNodes()).toEqual(before)
  })
})

import { drizzle } from 'drizzle-orm/postgres-js'
import postgres from 'postgres'
import * as schema from './schema'

const client = postgres(process.env.DATABASE_URL!, {
  ssl: process.env.NODE_ENV === 'production' ? 'require' : false,
  max: 5,
})
export const db = drizzle({ client, schema })

import * as bcrypt from 'bcryptjs'
import { Hono } from 'hono'
import { deleteCookie, setCookie } from 'hono/cookie'
import { jwt, sign } from 'hono/jwt'
import { ADMIN_EMAIL, ADMIN_PASSWORD_HASH, JWT_SECRET } from './credentials'
import { loginLimiter } from './loginLimiter'

/** Placeholder hash used when ADMIN_PASSWORD_HASH is not set — prevents timing attacks */
const PLACEHOLDER_HASH = '$2b$12$invalid.hash.placeholder.value.xx'

export const authRoutes = new Hono()

/**
 * POST /login
 * Validates admin credentials and issues a JWT in an httpOnly cookie.
 * Rate-limited to 5 attempts per 10-minute window per IP.
 */
authRoutes.post('/login', loginLimiter, async (c) => {
  const body = (await c.req.json().catch(() => ({}))) as Record<string, unknown>
  const email = typeof body.email === 'string' ? body.email : ''
  const password = typeof body.password === 'string' ? body.password : ''

  const emailMatch = email === ADMIN_EMAIL

  // Always run bcrypt.compare to prevent timing attacks, even when email doesn't match
  const hashToCompare = ADMIN_PASSWORD_HASH || PLACEHOLDER_HASH
  const passMatch = await bcrypt.compare(password, hashToCompare)

  if (!emailMatch || !passMatch) {
    return c.json({ error: 'Invalid credentials' }, 401)
  }

  const token = await sign(
    {
      sub: ADMIN_EMAIL,
      role: 'admin',
      exp: Math.floor(Date.now() / 1000) + 7200,
    },
    JWT_SECRET,
    'HS256',
  )

  setCookie(c, 'admin_token', token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'Lax',
    path: '/',
    maxAge: 7200,
  })

  return c.json({ ok: true }, 200)
})

/**
 * POST /logout
 * Clears the admin_token cookie server-side.
 */
authRoutes.post('/logout', (c) => {
  deleteCookie(c, 'admin_token', { path: '/' })
  return c.json({ ok: true })
})

/**
 * GET /me
 * Returns auth status for the current session.
 * Protected by JWT middleware — requires valid admin_token cookie.
 */
authRoutes.get('/me', jwt({ secret: JWT_SECRET, alg: 'HS256', cookie: 'admin_token' }), (c) => {
  return c.json({ authenticated: true })
})

/**
 * Core navigation graph type definitions for CampusNav.
 *
 * Two categories of types:
 *
 * 1. **ngraph.graph data types** — `NavNodeData` and `NavEdgeData` are the `.data`
 *    fields stored on ngraph.graph's Node and Link objects via
 *    `graph.addNode(id, data)` and `graph.addLink(from, to, data)`.
 *
 * 2. **Serialization types** — `NavNode`, `NavEdge`, `NavFloor`, `NavBuilding`,
 *    and `NavGraph` are the JSON shapes used for API transport (GET /api/map) and
 *    file storage. The client loads a `NavGraph`, iterates `buildings[].floors[]`,
 *    destructures each node/edge into `(id, data)`, and feeds them into ngraph.graph.
 *    `NavNode` objects live inside `NavFloor.nodes[]`.
 *
 * All coordinates are **NORMALIZED** (0.0–1.0), representing percentages of the
 * floor plan image dimensions. Convert to pixels only at render time:
 * `pixelX = node.x * canvasWidth`.
 */

// ============================================================
// Node Types
// ============================================================

/**
 * Classification of navigation nodes on a floor plan.
 *
 * **Visible to students** (searchable destinations):
 * - `room` — Classroom, office, lab
 * - `entrance` — Building entrance/exit
 * - `elevator` — Elevator (also an accessibility waypoint)
 * - `restroom` — Restroom
 * - `landmark` — Named point of interest (cafeteria, library)
 *
 * **Invisible to students** (routing infrastructure only):
 * - `stairs` — Stairwell navigation waypoint, HIDDEN from student map (routing infrastructure only)
 * - `ramp` — Ramp navigation waypoint, HIDDEN from student map (routing infrastructure only)
 * - `junction` — Hallway intersection
 * - `hallway` — Mid-hallway point
 */
export type NavNodeType =
  | 'room'
  | 'entrance'
  | 'elevator'
  | 'stairs'
  | 'ramp'
  | 'restroom'
  | 'junction'
  | 'hallway'
  | 'landmark'

/**
 * Data stored on each graph node (the `.data` field of an ngraph.graph Node).
 *
 * Coordinates are normalized 0.0–1.0: percentage of floor plan width/height.
 */
export interface NavNodeData {
  /** Normalized x position (0.0 = left edge, 1.0 = right edge of floor plan) */
  x: number
  /** Normalized y position (0.0 = top edge, 1.0 = bottom edge of floor plan) */
  y: number
  /** Display label for search results and turn-by-turn directions */
  label: string
  /** Node classification — determines visibility and search behavior */
  type: NavNodeType
  /** Whether this node appears in student search results */
  searchable: boolean
  /** ID of the floors record this node belongs to (FK → floors.id) */
  floorId: number
  // buildingName REMOVED — derived transitively via floor → building
  /** Room/office number identifier (e.g. "204", "A-102") */
  roomNumber?: string
  /** Human-readable description shown in location detail sheet */
  description?: string
  /** Accessibility information shown in detail sheet */
  accessibilityNotes?: string
  // Floor connector linkage — only set on stairs, elevator, ramp nodes
  /** ID of the floor above that this connector node links to */
  connectsToFloorAboveId?: number
  /** ID of the floor below that this connector node links to */
  connectsToFloorBelowId?: number
  /** ID of the corresponding node on the floor above */
  connectsToNodeAboveId?: string
  /** ID of the corresponding node on the floor below */
  connectsToNodeBelowId?: string
  /** ID of the building this campus entrance marker bridges to (campus map only, entrance nodes) */
  connectsToBuildingId?: number
}

// ============================================================
// Edge Types
// ============================================================

/**
 * Data stored on each graph edge (the `.data` field of an ngraph.graph Link).
 *
 * Every edge carries **dual weights** to enable accessibility routing:
 * - `standardWeight`: cost for the standard walking route
 * - `accessibleWeight`: cost for the wheelchair-accessible route
 *   (same as standard for flat paths; higher for detours like ramps;
 *   `Infinity` for non-accessible edges like stairs)
 */
export interface NavEdgeData {
  /**
   * Walking cost for the standard route.
   * Typically the Euclidean distance between connected nodes in normalized
   * coordinates. Can be overridden by an admin for non-straight paths.
   */
  standardWeight: number
  /**
   * Walking cost for the wheelchair-accessible route.
   * - Same as `standardWeight` for accessible paths.
   * - Higher than `standardWeight` if the accessible path is longer (e.g. ramp).
   * - `Infinity` for non-accessible edges (e.g. stairs without elevator).
   */
  accessibleWeight: number
  /** Whether this edge is traversable by wheelchair */
  accessible: boolean
  /** Whether this edge can be traversed in both directions */
  bidirectional: boolean
  /** Optional admin notes ("3 steps", "narrow doorway", "automatic door") */
  accessibilityNotes?: string
}

// ============================================================
// Serialization Types (API / JSON transport)
// ============================================================

/**
 * A serialized node for JSON transport (API responses, file storage).
 * Combines the node's unique ID with its data fields.
 * NavNode inherits `floorId` from NavNodeData — no direct change needed.
 */
export interface NavNode extends NavNodeData {
  /** Unique identifier for this node (e.g. "room-204", "entrance-main") */
  id: string
}

/**
 * A serialized edge for JSON transport (API responses, file storage).
 * Combines the edge's ID, endpoint references, and data fields.
 */
export interface NavEdge extends NavEdgeData {
  /** Unique identifier for this edge */
  id: string
  /** Source node ID */
  sourceId: string
  /** Target node ID */
  targetId: string
}

/**
 * Optional real-world GPS bounds used to project normalized floor coordinates
 * onto latitude/longitude space.
 */
export interface NavFloorGpsBounds {
  /** Minimum latitude represented by this floor map */
  minLat: number
  /** Maximum latitude represented by this floor map */
  maxLat: number
  /** Minimum longitude represented by this floor map */
  minLng: number
  /** Maximum longitude represented by this floor map */
  maxLng: number
}

/**
 * A single floor within a building, containing all nodes and edges on that floor.
 */
export interface NavFloor {
  /** Database ID of this floor record (floors.id) */
  id: number
  /** Floor number (1-based) */
  floorNumber: number
  /** Path to the floor plan image asset */
  imagePath: string
  /** ISO 8601 timestamp of last graph modification */
  updatedAt: string
  /** Optional GPS calibration bounds for this floor */
  gpsBounds?: NavFloorGpsBounds
  /** All navigation nodes on this floor */
  nodes: NavNode[]
  /** All navigation edges on this floor */
  edges: NavEdge[]
}

/**
 * A building containing one or more floors.
 */
export interface NavBuilding {
  /** Database ID of this building record (buildings.id) */
  id: number
  /** Display name of the building */
  name: string
  /** All floors within this building */
  floors: NavFloor[]
}

/**
 * Complete navigation graph as JSON — returned by `GET /api/map`.
 *
 * The client loads this on page init and builds an ngraph.graph instance
 * by iterating the nested buildings → floors → nodes/edges structure:
 * ```ts
 * const graph = createGraph<NavNodeData, NavEdgeData>()
 * for (const building of navGraph.buildings) {
 *   for (const floor of building.floors) {
 *     for (const { id, ...data } of floor.nodes) graph.addNode(id, data)
 *     for (const { id, sourceId, targetId, ...data } of floor.edges)
 *       graph.addLink(sourceId, targetId, data)
 *   }
 * }
 * ```
 */
export interface NavGraph {
  /** All buildings in the campus, each containing floors with nodes and edges */
  buildings: NavBuilding[]
  // nodes and edges now live under buildings[].floors[].nodes/edges
  // metadata replaced by floors[].updatedAt
}

